args.sparql:
SELECT ?player ?position ?height
WHERE {
  ?player wdt:P31 wd:Q563392 ;
          wdt:P27 wd:Q156 ;
          wdt:P2613 wd:Q30098645 ;
          wdt:P555 wd:Q243315 ;
          wdt:P297 ?position ;
          wdt:P2045 ?height .
}
ORDER BY ASC(?height)
LIMIT 1

SELECT ?player ?position ?spike_height
WHERE {
  ?team wdt:P555 wd:Q243315 ;
         wdt:P27 wd:Q156 ;
         wdt:P175 wd:Q9878 ;
         wdt:P31 wd:Q2582557 .
  ?player wdt:P122 ?team ;
          wdt:P31 wd:Q563392 ;
          wdt:P27 wd:Q156 ;
          wdt:P463 wd:Q2617479 ;
          wdt:P297 ?position ;
          wdt:P1368 ?spike_height .
}
ORDER BY ASC(?spike_height)
LIMIT 1
